#include <stdio.h>
#include <math.h>

int main() {
    int n;
    scanf("%d", &n);
    if (n <= 1) {
        printf("NO\n");
        return 0;
    }
    if (n == 2) {
        printf("YES\n");
        return 0;
    }
    if (n % 2 == 0) {
        printf("NO\n");
        return 0;
    }
    int isPrime = 1;
    int limit = (int)sqrt((double)n);
    int i = 3;
    while (i <= limit) {
        if (n % i == 0) {
            isPrime = 0;
            break;
        }
        i += 2;
    }
    printf(isPrime ? "YES\n" : "NO\n");
    return 0;
}

