const readline = require('readline').createInterface({
  input: process.stdin,
  output: process.stdout
});

let i = 0;
let input = [];
readline.on('line', line => {
  input.push(line);
});
readline.on('close', () => {
  main();
});

function main() {
  let n = parseInt(input[i++]);
  let isPrime = true;
  if (n <= 1) {
    console.log('NO');
  } else if (n === 2) {
    console.log('YES');
  } else if (n % 2 === 0) {
    console.log('NO');
  } else {
    const limit = Math.floor(Math.sqrt(n));
    let j = 3;
    while (j <= limit) {
      if (n % j === 0) {
        isPrime = false;
        break;
      }
      j += 2;
    }
    console.log(isPrime ? 'YES' : 'NO');
  }
}
